/* =========================
   TABS Zurich (sin scroll)
   Colores:
   - Base suave: #91bfe3
   - Normal (texto): #0f4c81
   - Active (texto + underline): #2167AE
   ========================= */
[selector="tab"] .row{
  margin: 0px 12px !important;
  display: flex !important;
  flex-wrap: nowrap !important;
  align-items: center;
  gap: 1.6rem;

  /* línea base */
  border-bottom: 2px solid #91bfe3;

  padding: 0 .75rem;

  /* ancho del underline (ajústalo) */
  --ul-w-hover: 85%;
  --ul-w-active: 90%;
}

/* Quitar overflow que genera scroll */
[selector="tab"] .row,
[selector="tab"] .row *{
  overflow: visible !important;
}

[selector="tab"] .form-group{
  margin: 0 !important;
  max-height: none !important;
}

/* Quitar gutters */
[selector="tab"] .row > [class*="col-"]{
  padding-left: 0 !important;
  padding-right: 0 !important;
}

/* Botón tipo tab */
[selector="tab"] .form-group > .btn.btn-primary{
  width: 100%;
  background: transparent !important;
  border: 0 !important;
  box-shadow: none !important;
  border-radius: 0 !important;

  /* normal Zurich */
  color: #0f4c81 !important;
  font-weight: 500;
  font-size: 1.05rem;

  /* para que el underline se “pegue” al borde inferior del contenedor */
  display: inline-flex;
  align-items: center;
  justify-content: center;

  padding: .75rem 0 .85rem;
  position: relative;
  transition: color .15s ease;
}

/* Underline: alineado EXACTO sobre la línea base */
[selector="tab"] .form-group > .btn.btn-primary::after{
  content: "";
  position: absolute;
  left: 50%;
  transform: translateX(-50%);

  /* clave: la base mide 2px, entonces lo bajo 2px para que quede encima exacto */
  bottom: -2px;

  height: 4px;
  width: 0;                 /* oculto por defecto */
  background: #0f4c81;      /* normal underline */
  transition: width .18s ease, background-color .15s ease;
}

/* Hover */
[selector="tab"] .form-group > .btn.btn-primary:hover{
  color: #0f4c81 !important;
}
[selector="tab"] .form-group > .btn.btn-primary:hover::after{
  width: var(--ul-w-hover);
  background: #0f4c81;
}

/* ACTIVE (3 posibles estados) */
[selector="tab"] .form-group > .btn.btn-primary.active,
[selector="tab"] .form-group[selected="selected"] > .btn.btn-primary,
[selector="tab"] .form-group[aria-selected="true"] > .btn.btn-primary{
  color: #2167AE !important;
  font-weight: 700;
}

[selector="tab"] .form-group > .btn.btn-primary.active::after,
[selector="tab"] .form-group[selected="selected"] > .btn.btn-primary::after,
[selector="tab"] .form-group[aria-selected="true"] > .btn.btn-primary::after{
  width: var(--ul-w-active);  /* <-- aquí regulas el ancho del active */
  background: #2167AE;        /* active underline */
}

/* Focus sin glow */
[selector="tab"] .form-group > .btn:focus,
[selector="tab"] .form-group > .btn:active{
  outline: none !important;
  box-shadow: none !important;
}


/* =========================
   ACTIVE por selector="tab-active"
   (si existe ese wrapper, ese tab queda como seleccionado)
   ========================= */
[selector="tab"] [selector="tab-active"] .form-group > .btn.btn-primary{
  color: #2167AE !important;
  font-weight: 700 !important;
}

[selector="tab"] [selector="tab-active"] .form-group > .btn.btn-primary::after{
  width: var(--ul-w-active) !important;
  background: #2167AE !important;
}


/* ==========================
   CONTENEDOR: Previous + Next en la MISMA FILA
   ========================== */

[selector="buttons-previous-next"] .col-sm-12{
  display: flex !important;
  justify-content: flex-start !important;  /* los manda a la derecha */
  align-items: center !important;
  gap: 10px;                             /* separación entre botones */
  margin: 18px 10px;
}

/* Evita scroll raro por overflow interno */
[selector="buttons-previous-next"] .form-group{
  margin: 0 !important;
  overflow: visible !important;
}

/* Ambos wrappers ya NO deben ocupar 100% */
[selector='button-previous'],
[selector='button-next']{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  margin: 0 !important;
}

[selector='button-previous'] > div,
[selector='button-next'] > div{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

/* ==========================
   BOTONES (mismo estilo)
   ========================== */

[selector='button-previous'] button.btn-primary,
[selector='button-next'] button.btn-primary{
  position: relative;
  display: inline-flex !important;
  align-items: center;
  justify-content: center;

  /* Tamaño tipo icon-button */
  width: 38px;
  height: 34px;
  padding: 0 !important;

  background-color: #2167AE !important;
  color: #fff !important;
  border: 1px solid #2167AE !important;
  border-radius: 8px;
  font-size: 18px;       /* hace la flecha más visible */
  font-weight: 700;
  line-height: 1;
  cursor: pointer;

  transition: background-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease;
}

/* QUITAR EL OJO (el pseudo elemento) */
[selector='button-previous'] button.btn-primary::before,
[selector='button-next'] button.btn-primary::before{
  content: none !important;
  display: none !important;
}

/* Hover */
[selector='button-previous'] button.btn-primary:hover,
[selector='button-next'] button.btn-primary:hover{
  background-color: #fff !important;
  color: #2167AE !important;
  border-color: #2167AE !important;
}

/* ==========================
   DISABLED: Previous / Next
   (mismo tamaño, gris #728092)
   ========================== */

/* Wrapper disabled (por si quieres mantener la misma fila) */
[selector="button-previous-next-disabled"]{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  margin: 0 !important;
}

[selector="button-previous-next-disabled"] > div{
  width: auto !important;
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

/* Botón gris */
[selector="button-previous-next-disabled"] button.btn-primary{
  width: 38px;
  height: 34px;
  padding: 0 !important;

  background-color: #728092 !important;
  border: 1px solid #728092 !important;
  color: #fff !important;

  border-radius: 8px;
  font-size: 18px;
  font-weight: 700;
  line-height: 1;

  cursor: not-allowed !important;
  opacity: 0.85;                 /* look disabled */
  pointer-events: none !important; /* no clic */
}

/* Asegurar que no aparezca el "ojo" */
[selector="button-previous-next-disabled"] button.btn-primary::before{
  content: none !important;
  display: none !important;
}

/* Sin hover (se queda gris) */
[selector="button-previous-next-disabled"] button.btn-primary:hover{
  background-color: #728092 !important;
  border-color: #728092 !important;
  color: #fff !important;
}










